"""Менеджер реестра моделей: добавление набора моделей без дубликатов, одно сохранение после набора."""from __future__ import annotationsimport mathfrom collections.abc import Iterablefrom pathlib import Pathfrom ..errors import EmptyModelCodeError, EmptyProviderErrorfrom ..models.llm_model import LLMModelfrom ..providers.llm_model_store import LLMModelStoredef _require_provider(provider: str) -> str:    """Нормализует provider (strip); поднимает EmptyProviderError, если пустой."""    p = (provider or "").strip()    if not p:        raise EmptyProviderError("provider cannot be empty")    return pdef _require_name(name: str) -> str:    """Нормализует name / код модели (strip); поднимает EmptyModelCodeError, если пустой."""    n = (name or "").strip()    if not n:        raise EmptyModelCodeError("model code cannot be empty")    return ndef _parse_model_key(model_key: str) -> tuple[str, str]:    """Разбирает ключ provider@name, возвращает (provider, name). Поднимает EmptyProviderError/EmptyModelCodeError при неверном формате."""    key = (model_key or "").strip()    if not key:        raise EmptyProviderError("model_key cannot be empty")    if "@" not in key:        raise EmptyModelCodeError("model_key must be in format provider@name")    provider, name = key.split("@", 1)    return (_require_provider(provider), _require_name(name))def _normalize_model_key(model_key: str) -> str:    """Нормализованный ключ provider@name для доступа к store."""    provider, name = _parse_model_key(model_key)    return f"{provider}@{name}"def _record_key(item: dict) -> str | None:    """Ключ записи: provider@name. None если provider или name пустые."""    provider = item.get("provider") or item.get("provider_code")    name = item.get("name") or item.get("code")    if provider is None or name is None:        return None    p = str(provider).strip()    n = str(name).strip()    if not p or not n:        return None    return f"{p}@{n}"def _record_sort_key(item: dict) -> tuple[str, int]:    """Ключ сортировки: (provider, -created). По провайдеру по возрастанию, по дате добавления по убыванию."""    provider = (item.get("provider") or item.get("provider_code") or "").strip()    created = item.get("created")    if created is None:        created = 0    try:        created = int(created)    except (TypeError, ValueError):        created = 0    return (provider, -created)class LLMModelManager:    """    Менеджер реестра: использует хранилище, путь к файлу по умолчанию из ModuleConfig (models_store_file).    Добавление моделей — только при отсутствии записи по ключу provider@name;    сохранение в файл один раз после обработки всего набора.    """    def __init__(self, store_file_path: Path | str | None = None) -> None:        self._store = LLMModelStore(store_file_path=store_file_path)        self._store.load()    @staticmethod    def optional_price_per_million(value: object) -> float | None:        """        Цена за 1M токенов из реестра/UI: не задана → None; ``0`` — допустима;        нечисло, nan, inf → None.        """        if value is None:            return None        try:            x = float(value)        except (TypeError, ValueError):            return None        if not math.isfinite(x):            return None        return x    @property    def store(self) -> LLMModelStore:        """Доступ к хранилищу реестра."""        return self._store    def exists(self, model_key: str) -> bool:        """Проверяет, есть ли в реестре запись с данным ключом provider@name."""        return _normalize_model_key(model_key) in self._store.data    def create_empty(        self,        model_key: str,        created: int | None = None,    ) -> dict:        """        Формирует запись модели с полями по умолчанию: can_update=True, enabled=True.        Формат записи задаётся LLMModel.to_registry_record(); created — timestamp (число).        """        provider, name = _parse_model_key(model_key)        model = LLMModel(            provider=provider,            name=name,            can_update=True,            enabled=True,        )        record = model.to_registry_record()        record["created"] = created        return record    def add_models(self, models: Iterable[dict]) -> int:        """        Добавляет записи в реестр только если записи с таким provider@name ещё нет.        После обработки всего набора один раз вызывает store.save().        Возвращает количество добавленных записей. Записи без валидного provider/name пропускаются.        """        existing_keys: set[str] = set(self._store.data.keys())        added = 0        for item in models:            if not isinstance(item, dict):                continue            k = _record_key(item)            if k is None or k in existing_keys:                continue            existing_keys.add(k)            self._store.data[k] = dict(item)            added += 1        if added:            self._store.save()        return added    def get_sorted_records(self) -> list[dict]:        """        Записи реестра, отсортированные по имени провайдера, затем по дате добавления (по убыванию).        Единая точка для получения списка моделей с нужной сортировкой.        """        records = [item for item in self._store.data.values() if isinstance(item, dict)]        return sorted(records, key=_record_sort_key)    def get_provider_codes(self) -> list[str]:        """Уникальные коды провайдеров из реестра (из store.data), в порядке появления в отсортированном списке."""        seen: set[str] = set()        codes: list[str] = []        for item in self.get_sorted_records():            p = (item.get("provider") or item.get("provider_code") or "").strip()            if p and p not in seen:                seen.add(p)                codes.append(p)        return codes    def get_model_keys(self, only_enabled: bool = True) -> list[str]:        """Список ключей записей в формате provider@name для выбора в UI. Сортировка: провайдер, затем дата по убыванию.        При only_enabled=True возвращаются только записи с enabled=True."""        sorted_items = sorted(            self._store.data.items(),            key=lambda kv: _record_sort_key(kv[1]),        )        if not only_enabled:            return [k for k, _ in sorted_items]        return [k for k, item in sorted_items if item.get("enabled", True)]    def get_model_names(self, provider: str) -> list[str]:        """Имена (коды) моделей для провайдера из реестра, по дате добавления по убыванию."""        p = _require_provider(provider)        prefix = f"{p}@"        sorted_items = sorted(            self._store.data.items(),            key=lambda kv: _record_sort_key(kv[1]),        )        return [key[len(prefix) :] for key, _ in sorted_items if key.startswith(prefix)]    def get_record(self, model_key: str) -> dict | None:        """Возвращает запись реестра по ключу provider@name или None."""        key = _normalize_model_key(model_key)        item = self._store.data.get(key)        if isinstance(item, dict):            return item        return None    def get_cost(        self,        model_key: str,        input_count: int,        total_count: int,    ) -> float | None:        """        Стоимость по записи реестра: input_count * price_input / 1_000_000 +        (total_count - input_count) * price_output / 1_000_000.        Выходные токены — как ``total_count - input_count``.        Цена ``0`` учитывается; не задана (None / нечисло) — компонент пропускается.        None, если записи нет или обе цены не заданы.        """        record = self.get_record(model_key)        if record is None:            return None        pi = self.optional_price_per_million(record.get("price_input"))        po = self.optional_price_per_million(record.get("price_output"))        if pi is None and po is None:            return None        output_billable = max(0, total_count - input_count)        total_cost = 0.0        if pi is not None:            total_cost += input_count * pi / 1_000_000        if po is not None:            total_cost += output_billable * po / 1_000_000        return total_cost    @staticmethod    def costs_from_price_per_million_tokens(        price_input_per_million: float | None,        price_output_per_million: float | None,        *,        prompt_tokens: int,        total_tokens: int,    ) -> tuple[float | None, float | None]:        """        Стоимость входа и выхода (USD) при известных ценах за 1M токенов.        Формула (как у ``get_cost``): ``prompt_tokens * price_in / 1e6``        + ``max(0, total_tokens - prompt_tokens) * price_out / 1e6``.        Всё, что не вход, тарифицируется по цене выхода (в т.ч. размышление в ``total``).        Цена ``0`` даёт нулевую стоимость компонента; не задана — ``None`` для этого компонента.        """        cost_in: float | None = None        cost_out: float | None = None        try:            p = max(0, int(prompt_tokens))            t = max(0, int(total_tokens))        except (TypeError, ValueError):            return None, None        out_toks = max(0, t - p)        pi = LLMModelManager.optional_price_per_million(price_input_per_million)        po = LLMModelManager.optional_price_per_million(price_output_per_million)        if pi is not None:            cost_in = p * pi / 1_000_000        if po is not None:            cost_out = out_toks * po / 1_000_000        return cost_in, cost_out    def get_token_billable_costs(        self,        model_key: str,        *,        prompt_tokens: int,        total_tokens: int,    ) -> tuple[float | None, float | None]:        """        Стоимость входа и выхода по ценам из записи реестра (USD за 1M токенов).        Выходные токены: ``total_tokens - prompt_tokens`` (как в ``get_cost``).        """        record = self.get_record(model_key)        if record is None:            return None, None        return self.costs_from_price_per_million_tokens(            record.get("price_input"),            record.get("price_output"),            prompt_tokens=prompt_tokens,            total_tokens=total_tokens,        )    def update_model(self, model_key: str, **fields: object) -> bool:        """        Обновляет поля записи по ключу provider@name. Сохраняет реестр.        Возвращает True, если запись найдена и обновлена.        """        key = _normalize_model_key(model_key)        item = self._store.data.get(key)        if not isinstance(item, dict):            return False        for k, v in fields.items():            item[k] = v        self._store.save()        return True    def update_user_model(self, model_key: str, **fields: object) -> bool:        """        Обновляет запись как пользовательскую правку.        Любое ручное редактирование фиксирует модель как пользовательскую и        запрещает bootstrap-перезапись из source через can_update=False.        """        fields["can_update"] = False        return self.update_model(model_key, **fields)